+function updateMobileInputToggleUi() {
+  if (!mobileKbToggle) return;
+  const keyboardMode = mobileInputMode === "keyboard";
+  mobileKbToggle.dataset.active = keyboardMode ? "true" : "false";
+  mobileKbToggle.setAttribute("aria-pressed", keyboardMode ? "true" : "false");
+  mobileKbToggle.title = keyboardMode
+    ? "Keyboard mode enabled (tap to switch to touch mode)"
+    : "Touch mode enabled (tap to switch to keyboard mode)";
+}
+
+function setMobileInputMode(mode, { focusTarget = true } = {}) {
+  const normalized = mode === "keyboard" ? "keyboard" : "touch";
+  if (!shouldUseMobileKeyboardProxy() && normalized === "keyboard") {
+    mobileInputMode = "touch";
+  } else {
+    mobileInputMode = normalized;
+  }
+  updateMobileInputToggleUi();
+  if (!focusTarget) return;
+  if (mobileInputMode === "keyboard") {
+    focusKeyboardProxyInput();
+  } else {
+    if (keyboardProxy && document.activeElement === keyboardProxy) {
+      keyboardProxy.blur();
+    }
+    focusCanvasInput();
+  }
+}
+
+function useMobileKeyboardForPointer(pointerType) {
+  return pointerType !== "mouse" && mobileInputMode === "keyboard" && shouldUseMobileKeyboardProxy();
+}
